record_types.code:
type lzma_allocator is record
   alloc : access function
        (arg1 : System.Address;
         arg2 : Interfaces.C.size_t;
         arg3 : Interfaces.C.size_t) return System.Address;
   free : access procedure (arg1 : System.Address; arg2 : System.Address);
   opaque : System.Address;
end record;

type lzma_stream is record
   next_in : access Ada.Streams.Stream_Element;
   avail_in : aliased Interfaces.C.size_t;
   total_in : aliased Long_Long_Integer;
   next_out : access Ada.Streams.Stream_Element;
   avail_out : aliased Interfaces.C.size_t;
   total_out : aliased Long_Long_Integer;
   allocator : access lzma_allocator;
   internal : System.Address;
   reserved_ptr1 : System.Address;
   reserved_ptr2 : System.Address;
   reserved_ptr3 : System.Address;
   reserved_ptr4 : System.Address;
   reserved_int1 : aliased Long_Long_Integer;
   reserved_int2 : aliased Long_Long_Integer;
   reserved_int3 : aliased Interfaces.C.size_t;
   reserved_int4 : aliased Interfaces.C.size_t;
   reserved_enum1 : aliased lzma_reserved_enum_type;
   reserved_enum2 : aliased lzma_reserved_enum_type;
end record;
